#version 330
out vec4 fC;in vec3 vDir;uniform float time;uniform float colorIntensity;float mod289(float x){return x-floor(x*(1.0/289.0))*289.0;}vec4 mod289(vec4 x){return x-floor(x*(1.0/289.0))*289.0;}vec4 perm(vec4 x){return mod289(((x*34.0)+1.0)*x);}float noise(vec3 p){vec3 a=floor(p);vec3 d=p-a;d=d*d*(3.0-2.0*d);vec4 b=a.xxyy+vec4(0.0,1.0,0.0,1.0);vec4 k1=perm(b.xyxy);vec4 k2=perm(k1.xyxy+b.zzww);vec4 c=k2+a.zzzz;vec4 k3=perm(c);vec4 k4=perm(c+1.0);vec4 o1=fract(k3*(1.0/41.0));vec4 o2=fract(k4*(1.0/41.0));vec4 o3=o2*d.z+o1*(1.0-d.z);vec2 o4=o3.yw*d.x+o3.xz*(1.0-d.x);return o4.y*d.y+o4.x*(1.0-d.y);}float fbm(vec3 p){return noise(p)*0.5+noise(p*2.02)*0.25+noise(p*4.03)*0.125;}void main(){vec3 dir=normalize(vDir);float d=fbm(dir*2.5+time*0.05);vec3 col1=vec3(0.01,0.0,0.05);vec3 col2=vec3(0.5,0.0,1.0);vec3 col3=vec3(0.0,0.8,0.9);vec3 col4=vec3(1.0,0.2,0.4); vec3 clCol;if(d<0.5){clCol=mix(col2,col3,d*2.0);}else{clCol=mix(col3,col4,(d-0.5)*2.0);}vec3 nebula=mix(col1,clCol*d,colorIntensity);vec3 finC=nebula*colorIntensity;fC=vec4(finC,1.0);}